namespace UniversityCourseCatalog.Models;

public class Department
{
    public int Id { get; set; }
    public string Name { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
}

namespace UniversityCourseCatalog.Models;

public class Course
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Code { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Credits { get; set; }
    public string Schedule { get; set; } = string.Empty;
    public string InstructorName { get; set; } = string.Empty;
    public string InstructorBio { get; set; } = string.Empty;
    public int DepartmentId { get; set; }
    public string DepartmentName { get; set; } = string.Empty;
    public bool IsFeatured { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string StudentName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z0-9]{6,10}$", ErrorMessage = "Student ID must be 6-10 uppercase alphanumeric characters.")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    [Range(1, int.MaxValue, ErrorMessage = "Please select a course.")]
    public int CourseId { get; set; }
}

using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Course> _courses;

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Name = "Computer Science", Code = "CS", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Name = "Mathematics", Code = "MATH", Description = "Study of numbers, structures, and patterns." },
            new() { Id = 3, Name = "Physics", Code = "PHYS", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Name = "English", Code = "ENG", Description = "Study of literature, writing, and language." },
            new() { Id = 5, Name = "History", Code = "HIST", Description = "Study of past events and their impact on civilization." }
        };

        _courses = new List<Course>
        {
            new() { Id = 1, Title = "Introduction to Programming", Code = "CS101", Description = "Learn the fundamentals of programming using C#. Topics include variables, control flow, data structures, and object-oriented programming principles.", Credits = 3, Schedule = "Mon/Wed/Fri 9:00–9:50 AM", InstructorName = "Dr. Sarah Chen", InstructorBio = "Dr. Chen has 15 years of experience in software engineering and education. She holds a Ph.D. from MIT and has published extensively on programming pedagogy.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 2, Title = "Data Structures and Algorithms", Code = "CS201", Description = "Advanced study of data organization and algorithmic problem-solving. Covers trees, graphs, sorting, searching, and complexity analysis.", Credits = 4, Schedule = "Tue/Thu 10:30 AM–12:00 PM", InstructorName = "Dr. James Park", InstructorBio = "Dr. Park specializes in algorithm design and competitive programming. He is a two-time ACM ICPC world finalist.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = true },
            new() { Id = 3, Title = "Database Systems", Code = "CS310", Description = "Design and implementation of database systems. Topics include relational model, SQL, normalization, transactions, and distributed databases.", Credits = 3, Schedule = "Mon/Wed 2:00–3:20 PM", InstructorName = "Dr. Maria Lopez", InstructorBio = "Dr. Lopez worked at Oracle for a decade before joining academia. Her research focuses on query optimization and NoSQL systems.", DepartmentId = 1, DepartmentName = "Computer Science", IsFeatured = false },
            new() { Id = 4, Title = "Calculus I", Code = "MATH101", Description = "Limits, derivatives, and integrals of single-variable functions. Applications to physics and engineering problems.", Credits = 4, Schedule = "Mon/Wed/Fri 10:00–10:50 AM", InstructorName = "Dr. Robert Klein", InstructorBio = "Dr. Klein is an award-winning educator with a passion for making calculus accessible. He has authored three widely-used textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = true },
            new() { Id = 5, Title = "Linear Algebra", Code = "MATH202", Description = "Vector spaces, linear transformations, matrices, determinants, eigenvalues, and applications to systems of equations.", Credits = 3, Schedule = "Tue/Thu 1:00–2:20 PM", InstructorName = "Dr. Anita Gupta", InstructorBio = "Dr. Gupta's research spans numerical linear algebra and machine learning. She consults regularly with tech companies on AI projects.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 6, Title = "Statistics and Probability", Code = "MATH301", Description = "Probability theory, random variables, distributions, hypothesis testing, and regression analysis.", Credits = 3, Schedule = "Mon/Wed 11:00 AM–12:20 PM", InstructorName = "Dr. Robert Klein", InstructorBio = "Dr. Klein is an award-winning educator with a passion for making calculus accessible. He has authored three widely-used textbooks.", DepartmentId = 2, DepartmentName = "Mathematics", IsFeatured = false },
            new() { Id = 7, Title = "Classical Mechanics", Code = "PHYS201", Description = "Newtonian mechanics, Lagrangian and Hamiltonian formulations, oscillations, and rigid body dynamics.", Credits = 4, Schedule = "Tue/Thu 9:00–10:20 AM", InstructorName = "Dr. Alan Foster", InstructorBio = "Dr. Foster is a theoretical physicist who previously worked at CERN. His lectures are known for vivid demonstrations and real-world applications.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = true },
            new() { Id = 8, Title = "Electromagnetism", Code = "PHYS301", Description = "Electric and magnetic fields, Maxwell's equations, electromagnetic waves, and optics.", Credits = 4, Schedule = "Mon/Wed/Fri 1:00–1:50 PM", InstructorName = "Dr. Nina Petrov", InstructorBio = "Dr. Petrov researches photonics and metamaterials. She holds multiple patents in optical communications technology.", DepartmentId = 3, DepartmentName = "Physics", IsFeatured = false },
            new() { Id = 9, Title = "Creative Writing", Code = "ENG210", Description = "Workshop-based course exploring fiction, poetry, and creative nonfiction. Emphasis on craft, revision, and peer feedback.", Credits = 3, Schedule = "Tue/Thu 3:00–4:20 PM", InstructorName = "Prof. David Okafor", InstructorBio = "Prof. Okafor is a published novelist and poet. His work has appeared in The New Yorker, Granta, and The Paris Review.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 10, Title = "American Literature", Code = "ENG305", Description = "Survey of American literature from the colonial period to the present, with attention to diverse voices and cultural contexts.", Credits = 3, Schedule = "Mon/Wed 3:30–4:50 PM", InstructorName = "Dr. Rachel Simmons", InstructorBio = "Dr. Simmons specializes in 20th-century American fiction and has received the departmental teaching excellence award three times.", DepartmentId = 4, DepartmentName = "English", IsFeatured = false },
            new() { Id = 11, Title = "World History: Ancient Civilizations", Code = "HIST101", Description = "Exploration of ancient civilizations including Mesopotamia, Egypt, Greece, Rome, China, and the Americas.", Credits = 3, Schedule = "Mon/Wed/Fri 11:00–11:50 AM", InstructorName = "Dr. Thomas Wren", InstructorBio = "Dr. Wren is an archaeologist and historian who has led excavations in Greece and Turkey. He brings artifacts and primary sources into the classroom.", DepartmentId = 5, DepartmentName = "History", IsFeatured = true },
            new() { Id = 12, Title = "Modern European History", Code = "HIST320", Description = "Europe from the French Revolution to the present. Topics include industrialization, world wars, decolonization, and European integration.", Credits = 3, Schedule = "Tue/Thu 11:00 AM–12:20 PM", InstructorName = "Dr. Clara Hoffman", InstructorBio = "Dr. Hoffman is a specialist in 20th-century European history with a focus on Franco-German relations and EU politics.", DepartmentId = 5, DepartmentName = "History", IsFeatured = false }
        };
    }

    public List<Department> GetAllDepartments() => _departments;

    public Department? GetDepartmentById(int id) => _departments.FirstOrDefault(d => d.Id == id);

    public List<Course> GetAllCourses() => _courses;

    public List<Course> GetFeaturedCourses() => _courses.Where(c => c.IsFeatured).ToList();

    public List<Course> GetCoursesByDepartment(int departmentId) =>
        _courses.Where(c => c.DepartmentId == departmentId).ToList();

    public Course? GetCourseById(int id) => _courses.FirstOrDefault(c => c.Id == id);

    public List<Course> SearchCourses(string? searchTerm, int? departmentId)
    {
        var query = _courses.AsEnumerable();

        if (departmentId.HasValue && departmentId.Value > 0)
            query = query.Where(c => c.DepartmentId == departmentId.Value);

        if (!string.IsNullOrWhiteSpace(searchTerm))
        {
            var term = searchTerm.Trim().ToLowerInvariant();
            query = query.Where(c =>
                c.Title.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Code.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.InstructorName.Contains(term, StringComparison.OrdinalIgnoreCase) ||
                c.Description.Contains(term, StringComparison.OrdinalIgnoreCase));
        }

        return query.ToList();
    }

    public bool SubmitEnrollmentRequest(EnrollmentRequest request)
    {
        // In a real application, this would persist to a database.
        return true;
    }
}

