@page "/"
@inject CatalogService CatalogService

<PageTitle>University Course Catalog</PageTitle>

<h1>Welcome to the University Course Catalog</h1>
<p class="lead">Explore our departments and courses, and submit your enrollment request online.</p>

<h2 class="mt-4">Featured Courses</h2>
<div class="row">
    @foreach (var course in featuredCourses)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@course.Code — @course.Title</h5>
                    <p class="card-text text-muted">@course.DepartmentName · @course.Credits credits</p>
                    <p class="card-text">@course.Description[..Math.Min(course.Description.Length, 120)]…</p>
                    <a href="courses/@course.Id" class="btn btn-primary btn-sm">View Details</a>
                </div>
            </div>
        </div>
    }
</div>

<h2 class="mt-5">Departments</h2>
<div class="row">
    @foreach (var dept in departments)
    {
        <div class="col-md-6 col-lg-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@dept.Name (@dept.Code)</h5>
                    <p class="card-text">@dept.Description</p>
                    <a href="courses?departmentId=@dept.Id" class="btn btn-outline-secondary btn-sm">Browse Courses</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    private List<Course> featuredCourses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        featuredCourses = CatalogService.GetFeaturedCourses();
        departments = CatalogService.GetAllDepartments();
    }
}

arguments.file_text:
@page "/courses"
@inject CatalogService CatalogService
@inject NavigationManager Navigation

<PageTitle>Course Catalog</PageTitle>

<h1>Course Catalog</h1>

<form method="get" action="courses" class="row g-3 mb-4">
    <div class="col-md-5">
        <input type="text" name="search" class="form-control" placeholder="Search by title, code, or instructor…" value="@Search" />
    </div>
    <div class="col-md-4">
        <select name="departmentId" class="form-select">
            <option value="">All Departments</option>
            @foreach (var dept in departments)
            {
                <option value="@dept.Id" selected="@(DepartmentId == dept.Id)">@dept.Name</option>
            }
        </select>
    </div>
    <div class="col-md-3">
        <button type="submit" class="btn btn-primary w-100">Search</button>
    </div>
</form>

@if (courses.Count == 0)
{
    <div class="alert alert-info">No courses found matching your criteria.</div>
}
else
{
    <table class="table table-striped table-hover">
        <thead>
            <tr>
                <th>Code</th>
                <th>Title</th>
                <th>Department</th>
                <th>Credits</th>
                <th>Instructor</th>
                <th></th>
            </tr>
        </thead>
        <tbody>
            @foreach (var course in courses)
            {
                <tr>
                    <td>@course.Code</td>
                    <td>@course.Title</td>
                    <td>@course.DepartmentName</td>
                    <td>@course.Credits</td>
                    <td>@course.InstructorName</td>
                    <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    [SupplyParameterFromQuery] public string? Search { get; set; }
    [SupplyParameterFromQuery] public int? DepartmentId { get; set; }

    private List<Course> courses = new();
    private List<Department> departments = new();

    protected override void OnInitialized()
    {
        departments = CatalogService.GetAllDepartments();
        courses = CatalogService.SearchCourses(Search, DepartmentId);
    }
}

@page "/courses/{Id:int}"
@inject CatalogService CatalogService

<PageTitle>@(course?.Title ?? "Course Not Found")</PageTitle>

@if (course is null)
{
    <div class="alert alert-warning">Course not found.</div>
}
else
{
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="courses">Courses</a></li>
            <li class="breadcrumb-item active" aria-current="page">@course.Code</li>
        </ol>
    </nav>

    <h1>@course.Code — @course.Title</h1>

    <div class="row mt-4">
        <div class="col-md-8">
            <h4>Description</h4>
            <p>@course.Description</p>

            <h4 class="mt-4">Schedule</h4>
            <p>@course.Schedule</p>

            <h4 class="mt-4">Credits</h4>
            <p>@course.Credits</p>

            <h4 class="mt-4">Department</h4>
            <p><a href="courses?departmentId=@course.DepartmentId">@course.DepartmentName</a></p>
        </div>
        <div class="col-md-4">
            <div class="card">
                <div class="card-body">
                    <h5 class="card-title">Instructor</h5>
                    <h6 class="card-subtitle mb-2 text-muted">@course.InstructorName</h6>
                    <p class="card-text">@course.InstructorBio</p>
                </div>
            </div>

            <div class="mt-3">
                <a href="enroll?courseId=@course.Id" class="btn btn-success w-100">Enroll in This Course</a>
            </div>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Course? course;

    protected override void OnInitialized()
    {
        course = CatalogService.GetCourseById(Id);
    }
}

@page "/enroll"
@inject CatalogService CatalogService

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Fill out the form below to submit your enrollment request.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <strong>Success!</strong> Your enrollment request has been submitted. You will receive confirmation via your university email.
    </div>
    <a href="courses" class="btn btn-primary">Back to Courses</a>
}
else
{
    <div class="row">
        <div class="col-md-8 col-lg-6">
            <form method="post" @formname="enrollment" @onsubmit="HandleSubmit">
                <AntiforgeryToken />

                <div class="mb-3">
                    <label for="studentName" class="form-label">Full Name</label>
                    <input type="text" class="form-control" id="studentName" name="Model.StudentName" value="@Model.StudentName" required />
                    @if (errors.ContainsKey(nameof(Model.StudentName)))
                    {
                        <div class="text-danger mt-1">@errors[nameof(Model.StudentName)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="studentId" class="form-label">Student ID</label>
                    <input type="text" class="form-control" id="studentId" name="Model.StudentId" value="@Model.StudentId" required placeholder="e.g., ABC12345" />
                    @if (errors.ContainsKey(nameof(Model.StudentId)))
                    {
                        <div class="text-danger mt-1">@errors[nameof(Model.StudentId)]</div>
                    }
                </div>

                <div class="mb-3">
                    <label for="courseId" class="form-label">Course</label>
                    <select class="form-select" id="courseId" name="Model.CourseId" required>
                        <option value="">— Select a course —</option>
                        @foreach (var course in courses)
                        {
                            <option value="@course.Id" selected="@(Model.CourseId == course.Id)">@course.Code — @course.Title</option>
                        }
                    </select>
                    @if (errors.ContainsKey(nameof(Model.CourseId)))
                    {
                        <div class="text-danger mt-1">@errors[nameof(Model.CourseId)]</div>
                    }
                </div>

                <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
                <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
            </form>
        </div>
    </div>
}

@code {
    [SupplyParameterFromQuery] public int? CourseId { get; set; }

    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    private List<Course> courses = new();
    private bool submitted;
    private Dictionary<string, string> errors = new();

    protected override void OnInitialized()
    {
        courses = CatalogService.GetAllCourses();
        if (CourseId.HasValue && Model.CourseId == 0)
        {
            Model.CourseId = CourseId.Value;
        }
    }

    private void HandleSubmit()
    {
        errors.Clear();

